const q=new URLSearchParams(location.search),avatarFallback='default-avatar.png';
const S={user:null,profile:null,role:'student',grades:[],subjects:[],teachers:[],exams:[],courses:[],managers:[],lessons:[],sessions:[],enrollments:[],requests:[],examResults:[],selectedManagers:[],editingCourseId:null,editingSessionId:null,activeCourseId:null,existingCoverUrl:'',submissionContext:null,studentDirectory:null};
const E={toolbar:document.getElementById('toolbar'),keyword:document.getElementById('keyword'),gradeFilter:document.getElementById('gradeFilter'),subjectFilter:document.getElementById('subjectFilter'),statusFilter:document.getElementById('statusFilter'),openCreateBtn:document.getElementById('openCreateBtn'),grid:document.getElementById('grid'),empty:document.getElementById('empty'),totalValue:document.getElementById('totalValue'),openValue:document.getElementById('openValue'),courseModal:document.getElementById('courseModal'),courseForm:document.getElementById('courseForm'),courseModalTitle:document.getElementById('courseModalTitle'),courseGrade:document.getElementById('courseGrade'),courseSubject:document.getElementById('courseSubject'),courseTuitionFee:document.getElementById('courseTuitionFee'),managerPicker:document.getElementById('managerPicker'),selectedManagers:document.getElementById('selectedManagers'),coverPreview:document.getElementById('coverPreview'),courseCoverFile:document.getElementById('courseCoverFile'),sessionModal:document.getElementById('sessionModal'),sessionForm:document.getElementById('sessionForm'),sessionModalTitle:document.getElementById('sessionModalTitle'),sessionExamId:document.getElementById('sessionExamId'),screen:document.getElementById('courseScreen'),screenTitle:document.getElementById('screenTitle'),screenRegisterBtn:document.getElementById('screenRegisterBtn'),bannerRegisterBtn:document.getElementById('bannerRegisterBtn'),registerBanner:document.getElementById('registerBanner'),screenEditBtn:document.getElementById('screenEditBtn'),openSessionBtn:document.getElementById('openSessionBtn'),summaryBox:document.getElementById('summaryBox'),courseStudentPanel:document.getElementById('courseStudentPanel'),sessionList:document.getElementById('sessionList'),submissionModal:document.getElementById('submissionModal'),submissionModalTitle:document.getElementById('submissionModalTitle'),submissionBody:document.getElementById('submissionBody')};
E.openCreateBtn.addEventListener('click',openCreateCourseModal);document.getElementById('addManagerBtn').addEventListener('click',addSelectedManager);E.courseForm.addEventListener('submit',submitCourseForm);E.sessionForm.addEventListener('submit',submitSessionForm);E.screenRegisterBtn.addEventListener('click',()=>registerCourse(S.activeCourseId));E.bannerRegisterBtn.addEventListener('click',()=>registerCourse(S.activeCourseId));E.screenEditBtn.addEventListener('click',()=>S.activeCourseId&&openEditCourseModal(S.activeCourseId));E.openSessionBtn.addEventListener('click',()=>openSessionModal());E.courseCoverFile.addEventListener('change',previewCover);[E.keyword,E.gradeFilter,E.subjectFilter,E.statusFilter].forEach(el=>el.addEventListener('input',renderCourses));init();
async function init(){const user=await window.AppAuth?.getUser?.();if(!user){location.href='index.html';return;}S.user=user;const{data:p}=await sb.from('users').select('id,role,full_name,email').eq('id',user.id).single();S.profile=p||null;S.role=p?.role||'student';if(S.role==='student'){E.keyword.classList.add('hidden');E.statusFilter.classList.add('hidden');E.openCreateBtn.classList.add('hidden');E.toolbar.style.gridTemplateColumns='repeat(2,minmax(150px,220px))'}else if(E.openCreateBtn){E.openCreateBtn.classList.toggle('hidden',S.role!=='admin')}await Promise.all([loadBase(),loadData()]);const courseId=q.get('courseId');const focus=q.get('focus');if(courseId)openCourseScreen(courseId);else if(focus==='requests'&&S.role==='admin'){const pendingReq=(S.requests||[]).find(item=>item.status==='pending'&&item.course_id);if(pendingReq)openCourseScreen(pendingReq.course_id)}}
async function loadBase(){const[{data:g},{data:su},{data:t},{data:ex}]=await Promise.all([sb.from('grades').select('id,name').order('name'),sb.from('subjects').select('id,name,grade_id').order('name'),sb.from('users').select('id,full_name,avatar_url,subject,role').in('role',['teacher','admin']).order('full_name'),sb.from('exams').select('id,title,total_points,duration_minutes').order('created_at',{ascending:false})]);S.grades=g||[];S.subjects=su||[];S.teachers=(t||[]).filter(x=>x.role==='teacher'||x.role==='admin');S.exams=ex||[];fillSelect(E.gradeFilter,S.grades,'Tất cả khối');fillSelect(E.courseGrade,S.grades,'Chọn khối');fillSubjects(E.subjectFilter,'','Tất cả môn');fillSubjects(E.courseSubject,'','Chọn môn');fillTeachers();fillExams();E.gradeFilter.addEventListener('change',()=>{fillSubjects(E.subjectFilter,E.gradeFilter.value,'Tất cả môn');renderCourses()});E.courseGrade.addEventListener('change',()=>fillSubjects(E.courseSubject,E.courseGrade.value,'Chọn môn'))}
async function loadData(){const cq=S.role==='student'?sb.from('courses').select('*').eq('status','open').order('created_at',{ascending:false}):sb.from('courses').select('*').order('created_at',{ascending:false});const eq=S.role==='student'?sb.from('course_enrollments').select('*').eq('student_id',S.user.id):sb.from('course_enrollments').select('*');const qq=S.role==='student'?sb.from('course_registration_requests').select('*').eq('student_id',S.user.id):sb.from('course_registration_requests').select('*');const rq=S.role==='student'?sb.from('exam_results').select('id,exam_id,student_id,course_id,submitted_at,score_auto,score_essay,score_total,seconds_left,attempt_no').eq('student_id',S.user.id):sb.from('exam_results').select('id,exam_id,student_id,course_id,submitted_at,score_auto,score_essay,score_total,seconds_left,attempt_no');const[{data:c},{data:m},{data:l},{data:ss},{data:e},{data:qrows},{data:r}]=await Promise.all([cq,sb.from('course_managers').select('*'),sb.from('lessons').select('*'),sb.from('course_sessions').select('*').order('session_order'),eq,qq.order('created_at',{ascending:false}),rq]);S.courses=c||[];S.managers=m||[];S.lessons=l||[];S.sessions=ss||[];S.enrollments=e||[];S.requests=qrows||[];S.examResults=r||[];renderCourses();if(S.activeCourseId)openCourseScreen(S.activeCourseId)}
function fillSelect(el,items,ph){el.innerHTML=`<option value="">${ph}</option>`+items.map(x=>`<option value="${x.id}">${esc(x.name)}</option>`).join('')}
function fillSubjects(el,gradeId,ph){const list=gradeId?S.subjects.filter(x=>x.grade_id===gradeId):S.subjects;el.innerHTML=`<option value="">${ph}</option>`+list.map(x=>`<option value="${x.id}">${esc(x.name)}</option>`).join('')}
function fillTeachers(){E.managerPicker.innerHTML=`<option value="">Chọn giáo viên quản lý</option>`+S.teachers.map(x=>`<option value="${x.id}">${esc(x.full_name||'Giáo viên')}${x.subject?` - ${esc(x.subject)}`:''}</option>`).join('')}
function fillExams(selected=''){E.sessionExamId.innerHTML=`<option value="">Chưa gắn đề luyện tập</option>`+S.exams.map(x=>`<option value="${x.id}" ${selected===x.id?'selected':''}>${esc(x.title)}</option>`).join('')}
function getManagers(courseId){const ids=S.managers.filter(x=>x.course_id===courseId).map(x=>x.teacher_id);return ids.map(id=>S.teachers.find(t=>t.id===id)).filter(Boolean)}
function isEnrolled(courseId){return S.role==='student'&&S.enrollments.some(x=>x.course_id===courseId&&x.student_id===S.user.id)}
function getPendingRequest(courseId){return S.requests.find(x=>x.course_id===courseId&&x.student_id===S.user.id&&x.status==='pending')}
function getCourseResults(courseId,examId=''){return S.examResults.filter(x=>x.course_id===courseId&&(!examId||x.exam_id===examId))}
function fmtDate(v){if(!v)return'Chưa thiết lập';const d=new Date(v);return Number.isNaN(d.getTime())?'Chưa thiết lập':d.toLocaleDateString('vi-VN')}
function fmtDateTime(v){if(!v)return'—';const d=new Date(v);return Number.isNaN(d.getTime())?'—':d.toLocaleString('vi-VN')}
function fmtMoney(v){const num=Number(v||0);return Number.isFinite(num)&&num>0?new Intl.NumberFormat('vi-VN').format(num)+'đ':'Chưa cập nhật'}
function normalizeSearch(v){return String(v||'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/đ/g,'d').replace(/Đ/g,'D').toLowerCase().trim()}
function esc(v){return String(v??'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;')}
function escAttr(v){return esc(v).replace(/`/g,'&#96;')}
function linkify(t){return t.replace(/(https?:\/\/[^\s<]+)/g,'<a href="$1" target="_blank" rel="noopener">$1</a>')}
function renderCourses(){const k=(E.keyword.value||'').trim().toLowerCase(),g=E.gradeFilter.value,s=E.subjectFilter.value,st=S.role==='student'?'open':E.statusFilter.value;const list=S.courses.filter(c=>{const mt=getManagers(c.id).map(t=>`${t.full_name||''} ${t.subject||''}`).join(' ').toLowerCase(),txt=`${c.name||''} ${c.description||''}`.toLowerCase();if(k&&!(`${txt} ${mt}`).includes(k))return false;if(g&&c.grade_id!==g)return false;if(s&&c.subject_id!==s)return false;if(st&&c.status!==st)return false;return true});if(E.totalValue)E.totalValue.textContent=String(S.courses.length);if(E.openValue)E.openValue.textContent=String(S.courses.filter(c=>c.status==='open').length);E.empty.classList.toggle('hidden',list.length>0);E.grid.innerHTML=list.map(renderCourseCard).join('');document.querySelectorAll('[data-open]').forEach(b=>b.onclick=()=>openCourseScreen(b.dataset.open));document.querySelectorAll('[data-edit]').forEach(b=>b.onclick=()=>openEditCourseModal(b.dataset.edit));document.querySelectorAll('[data-delete]').forEach(b=>b.onclick=()=>deleteCourse(b.dataset.delete));document.querySelectorAll('[data-register]').forEach(b=>b.onclick=()=>registerCourse(b.dataset.register))}
function renderCourseCard(c){const grade=S.grades.find(x=>x.id===c.grade_id)?.name||'Chưa thiết lập',subject=S.subjects.find(x=>x.id===c.subject_id)?.name||'Chưa thiết lập',managers=getManagers(c.id),enrolled=isEnrolled(c.id),pendingRequest=getPendingRequest(c.id),cnt=S.sessions.filter(x=>x.course_id===c.id).length||c.planned_sessions||0,style=c.cover_url?`style="background-image:linear-gradient(180deg,rgba(10,20,40,.12),rgba(10,20,40,.5)),url('${escAttr(c.cover_url)}');background-size:cover;background-position:center"`:'';return `<article class="course-card"><div class="cover" ${style}><div class="chips"><span class="pill light">${c.status==='open'?'Mở':'Đóng'}</span>${c.is_home_pinned?`<span class="pill light">Ghim Trang chủ</span>`:''}${S.role==='student'&&enrolled?`<span class="pill light">Đã được thêm</span>`:''}${S.role==='student'&&!enrolled&&pendingRequest?`<span class="pill light">Đã gửi yêu cầu</span>`:''}</div><div><h3 style="margin:0;font-size:1.18rem;line-height:1.35">${esc(c.name)}</h3><div style="margin-top:4px;font-size:.84rem;color:rgba(255,255,255,.8)">${fmtDate(c.start_date)} - ${fmtDate(c.end_date)}</div></div></div><div class="course-body"><p style="margin:0;color:#607089;line-height:1.6">${linkify(esc(c.description||'Chưa có mô tả cho khóa học này.'))}</p><div class="meta"><div><span>Khối / Môn</span><strong>${esc(grade)} - ${esc(subject)}</strong></div><div><span>Học phí</span><strong>${fmtMoney(c.tuition_fee)}</strong></div><div><span>Số buổi</span><strong>${cnt} buổi</strong></div><div><span>Cách vào học</span><strong>${S.role==='student'?(enrolled?'Đã được thêm':pendingRequest?'Đang chờ admin duyệt':'Gửi yêu cầu đăng ký'):'Admin thêm thủ công'}</strong></div></div><div class="teachers">${managers.length?managers.map(t=>`<span class="teacher"><img src="${escAttr(t.avatar_url||avatarFallback)}"><span>${esc(t.full_name||'Giáo viên')}</span></span>`).join(''):`<span class="muted">Chưa gán giáo viên quản lý</span>`}</div><div class="actions"><button class="btn btn-outline" type="button" data-open="${c.id}">Xem chi tiết</button>${S.role==='student'&&!enrolled&&!pendingRequest?`<button class="btn btn-primary" type="button" data-register="${c.id}">Gửi yêu cầu đăng ký</button>`:''}${S.role==='admin'?`<button class="btn btn-outline" type="button" data-edit="${c.id}">Sửa khóa</button><button class="btn btn-danger" type="button" data-delete="${c.id}">Xóa</button>`:''}</div></div></article>`}
function openCreateCourseModal(){if(S.role!=='admin')return;S.editingCourseId=null;S.selectedManagers=[];S.existingCoverUrl='';E.courseModalTitle.textContent='Tạo khóa học';E.courseForm.reset();setPreview('');fillSubjects(E.courseSubject,'','Chọn môn');renderSelectedManagers();E.courseModal.classList.add('show')}
function openEditCourseModal(courseId){const c=S.courses.find(x=>x.id===courseId);if(!c)return;S.editingCourseId=courseId;S.selectedManagers=getManagers(courseId).map(t=>t.id);S.existingCoverUrl=c.cover_url||'';E.courseModalTitle.textContent='Sửa khóa học';document.getElementById('courseName').value=c.name||'';document.getElementById('courseStatus').value=c.status||'open';document.getElementById('courseStartDate').value=c.start_date||'';document.getElementById('courseEndDate').value=c.end_date||'';document.getElementById('coursePlannedSessions').value=c.planned_sessions||30;E.courseTuitionFee.value=c.tuition_fee||'';document.getElementById('courseDescription').value=c.description||'';document.getElementById('coursePinned').checked=!!c.is_home_pinned;E.courseGrade.value=c.grade_id||'';fillSubjects(E.courseSubject,c.grade_id||'','Chọn môn');E.courseSubject.value=c.subject_id||'';E.courseCoverFile.value='';setPreview(c.cover_url||'');renderSelectedManagers();E.courseModal.classList.add('show')}
function closeCourseModal(){E.courseModal.classList.remove('show')}
function setPreview(url){E.coverPreview.innerHTML=url?`<img src="${escAttr(url)}">`:'<span>Chưa chọn ảnh bìa</span>'}
function previewCover(ev){const f=ev.target.files?.[0];if(!f){setPreview(S.existingCoverUrl||'');return;}const r=new FileReader();r.onload=e=>setPreview(e.target.result);r.readAsDataURL(f)}
function addSelectedManager(){const id=E.managerPicker.value;if(!id)return alert('Hãy chọn giáo viên trước khi thêm.');if(!S.selectedManagers.includes(id))S.selectedManagers.push(id);E.managerPicker.value='';renderSelectedManagers()}
function removeSelectedManager(id){S.selectedManagers=S.selectedManagers.filter(x=>x!==id);renderSelectedManagers()}
function renderSelectedManagers(){E.selectedManagers.innerHTML=S.selectedManagers.length?S.selectedManagers.map(id=>{const t=S.teachers.find(x=>x.id===id);if(!t)return'';return `<span class="teacher"><img src="${escAttr(t.avatar_url||avatarFallback)}"><span>${esc(t.full_name||'Giáo viên')}</span><button class="btn btn-outline btn-sm" type="button" onclick="removeSelectedManager('${id}')">Xóa</button></span>`}).join(''):'<span class="muted">Chưa gán giáo viên quản lý.</span>'}
async function submitCourseForm(ev){ev.preventDefault();if(S.role!=='admin')return;const name=document.getElementById('courseName').value.trim();if(!name)return alert('Tên khóa học không được để trống.');const tuitionFee=Number(E.courseTuitionFee.value||0);if(!Number.isFinite(tuitionFee)||tuitionFee<=0)return alert('Khóa học phải có học phí lớn hơn 0.');let coverUrl=S.existingCoverUrl||null;const file=E.courseCoverFile.files?.[0];if(file){const folder=S.editingCourseId||crypto.randomUUID(),path=`covers/${folder}/${Date.now()}-${file.name}`.replace(/\s+/g,'-');const{error:uErr}=await sb.storage.from('course-covers').upload(path,file,{upsert:true});if(uErr)return alert("Không thể upload ảnh bìa. Hãy kiểm tra bucket 'course-covers'. Lỗi: "+uErr.message);coverUrl=sb.storage.from('course-covers').getPublicUrl(path).data.publicUrl}const payload={name,description:document.getElementById('courseDescription').value.trim(),grade_id:E.courseGrade.value||null,subject_id:E.courseSubject.value||null,start_date:document.getElementById('courseStartDate').value||null,end_date:document.getElementById('courseEndDate').value||null,planned_sessions:Number(document.getElementById('coursePlannedSessions').value||0),tuition_fee:tuitionFee,status:document.getElementById('courseStatus').value,is_home_pinned:document.getElementById('coursePinned').checked,cover_url:coverUrl,created_by:S.user.id};let courseId=S.editingCourseId;const isNewCourse=!courseId;if(courseId){const{error}=await sb.from('courses').update({...payload,updated_at:new Date().toISOString()}).eq('id',courseId);if(error)return alert('Không thể cập nhật khóa học: '+error.message);await sb.from('course_managers').delete().eq('course_id',courseId)}else{const{data,error}=await sb.from('courses').insert(payload).select('id').single();if(error)return alert('Không thể tạo khóa học: '+error.message);courseId=data.id}if(S.selectedManagers.length){const rows=S.selectedManagers.map(id=>({course_id:courseId,teacher_id:id,assigned_by:S.user.id}));const{error}=await sb.from('course_managers').insert(rows);if(error)alert('Khóa học đã lưu nhưng chưa gán được giáo viên quản lý: '+error.message)}await window.AppAdminTools?.recordAudit?.(isNewCourse?'course_created':'course_updated',{target_type:'course',target_id:courseId,course_name:name,status:payload.status,manager_count:S.selectedManagers.length,planned_sessions:payload.planned_sessions,tuition_fee:payload.tuition_fee});if(isNewCourse&&payload.status==='open'&&window.NotificationHelper){try{await window.NotificationHelper.notifyAllStudents({type:'course_created',title:'Có khóa học mới dành cho bạn',message:`Khóa học "${name}" vừa được mở đăng ký.`,refId:courseId,targetUrl:`courses.html?courseId=${encodeURIComponent(courseId)}`,meta:{courseId,courseName:name}})}catch(error){console.warn('Không gửi được thông báo khóa học mới',error)}}closeCourseModal();await loadData()}
async function deleteCourse(courseId){if(S.role!=='admin')return;if(!confirm('Bạn có chắc muốn xóa khóa học này không?'))return;const course=S.courses.find(x=>x.id===courseId);const{error}=await sb.from('courses').delete().eq('id',courseId);if(error)return alert('Không thể xóa khóa học: '+error.message);await window.AppAdminTools?.recordAudit?.('course_deleted',{target_type:'course',target_id:courseId,course_name:course?.name||null});closeCourseScreen();await loadData()}
async function ensureStudentDirectory(){if(S.studentDirectory)return S.studentDirectory;const{data,error}=await sb.from('users').select('id,full_name,email').eq('role','student').order('full_name');if(error)throw error;S.studentDirectory=data||[];return S.studentDirectory}
function getCourseEnrollmentRows(courseId){return S.enrollments.filter(x=>x.course_id===courseId)}
function getCourseEnrollmentMap(courseId){return new Set(getCourseEnrollmentRows(courseId).map(x=>x.student_id))}
function getEnrolledStudents(courseId){const enrolledIds=getCourseEnrollmentMap(courseId);return (S.studentDirectory||[]).filter(x=>enrolledIds.has(x.id))}
function getCourseRequests(courseId){return S.requests.filter(x=>x.course_id===courseId)}
function renderCourseStudentPanel(courseId,keyword='',options={}){if(S.role!=='admin'||!E.courseStudentPanel)return;const {keepSearchFocus=false}=options;const enrolled=getEnrolledStudents(courseId);const enrolledIds=getCourseEnrollmentMap(courseId);const q=normalizeSearch(keyword);const requests=getCourseRequests(courseId);const pendingRequests=requests.filter(x=>x.status==='pending');const requestStudents=pendingRequests.map(req=>{const student=(S.studentDirectory||[]).find(x=>x.id===req.student_id);return {req,student};}).filter(x=>x.student);const pendingHeader=requestStudents.length?`<div style="display:flex;justify-content:space-between;align-items:center;gap:10px;flex-wrap:wrap;margin-bottom:8px"><div class="muted">Yêu cầu đăng ký đang chờ duyệt</div><div style="display:flex;gap:8px;flex-wrap:wrap"><button class="btn btn-outline btn-sm" type="button" onclick="rejectAllCourseRequests()">Từ chối tất cả</button><button class="btn btn-primary btn-sm" type="button" onclick="approveAllCourseRequests()">Duyệt tất cả</button></div></div>`:`<div class="muted" style="margin-bottom:8px">Yêu cầu đăng ký đang chờ duyệt</div>`;const candidates=(S.studentDirectory||[]).filter(student=>{if(enrolledIds.has(student.id))return false;if(requests.some(req=>req.student_id===student.id&&req.status==='pending'))return false;if(!q)return false;const haystack=normalizeSearch(`${student.full_name||''} ${student.email||''}`);return haystack.includes(q)}).slice(0,8);E.courseStudentPanel.classList.remove('hidden');E.courseStudentPanel.innerHTML=`<div style="display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap;margin-bottom:14px"><h4 style="margin:0">Học sinh trong khóa học</h4><span class="pill soft">${enrolled.length} học sinh</span></div><div style="display:grid;gap:16px"><div>${pendingHeader}<div style="display:grid;gap:8px">${requestStudents.length?requestStudents.map(({req,student})=>`<div style="display:flex;justify-content:space-between;align-items:center;gap:12px;padding:10px 12px;border:1px solid rgba(245,158,11,.22);border-radius:14px;background:#fff7ed"><div><div style="font-weight:700;color:var(--navy)">${esc(student.full_name||'Học sinh')}</div><div class="muted">${esc(student.email||'Chưa có email')} • ${fmtDateTime(req.created_at)}</div></div><div style="display:flex;gap:8px;flex-wrap:wrap"><button class="btn btn-primary btn-sm" type="button" onclick="approveCourseRequest('${req.id}')">Duyệt</button><button class="btn btn-outline btn-sm" type="button" onclick="rejectCourseRequest('${req.id}')">Từ chối</button></div></div>`).join(''):`<div class="muted" style="padding:6px 2px">Chưa có yêu cầu đăng ký nào.</div>`}</div></div><div><input id="courseStudentSearch" class="input" placeholder="Tìm học sinh theo tên hoặc email để thêm vào khóa học" value="${escAttr(keyword)}" oninput="filterCourseStudents(this.value)"><div id="courseStudentResults" style="display:grid;gap:8px;margin-top:10px">${q?candidates.length?candidates.map(student=>`<div style="display:flex;justify-content:space-between;align-items:center;gap:12px;padding:10px 12px;border:1px solid rgba(39,58,91,.08);border-radius:14px;background:#f8fbff"><div><div style="font-weight:700;color:var(--navy)">${esc(student.full_name||'Học sinh')}</div><div class="muted">${esc(student.email||'Chưa có email')}</div></div><button class="btn btn-primary btn-sm" type="button" onclick="addStudentToCourse('${student.id}')">Thêm vào khóa học</button></div>`).join(''):`<div class="muted" style="padding:6px 2px">Không tìm thấy học sinh phù hợp.</div>`:`<div class="muted" style="padding:6px 2px">Nhập tên hoặc email để tìm học sinh.</div>`}</div></div><div><div class="muted" style="margin-bottom:8px">Danh sách đã được thêm</div><div style="display:grid;gap:8px">${enrolled.length?enrolled.map(student=>`<div style="display:flex;justify-content:space-between;align-items:center;gap:12px;padding:10px 12px;border:1px solid rgba(39,58,91,.08);border-radius:14px;background:#fff"><div><div style="font-weight:700;color:var(--navy)">${esc(student.full_name||'Học sinh')}</div><div class="muted">${esc(student.email||'Chưa có email')}</div></div><span class="pill soft">Đã trong khóa</span></div>`).join(''):`<div class="muted" style="padding:6px 2px">Chưa có học sinh nào trong khóa học này.</div>`}</div></div></div>`;if(keepSearchFocus){const searchInput=document.getElementById('courseStudentSearch');if(searchInput){const pos=String(keyword).length;requestAnimationFrame(()=>{searchInput.focus();searchInput.setSelectionRange(pos,pos);});}}}
async function registerCourse(courseId){if(!courseId||S.role!=='student')return;const course=S.courses.find(x=>x.id===courseId);if(!course)return;if(isEnrolled(courseId))return alert('Bạn đã được thêm vào khóa học này rồi.');if(getPendingRequest(courseId))return alert('Bạn đã gửi yêu cầu đăng ký khóa học này rồi.');if(Number(course.tuition_fee||0)<=0)return alert('Khóa học này chưa cập nhật học phí nên chưa thể gửi đăng ký.');const { error }=await sb.from('course_registration_requests').insert({course_id:courseId,student_id:S.user.id,message:`Em muốn đăng ký khóa học "${course.name}"`,status:'pending'});if(error)return alert('Không thể gửi yêu cầu đăng ký: '+error.message);S.requests.unshift({course_id:courseId,student_id:S.user.id,message:`Em muốn đăng ký khóa học "${course.name}"`,status:'pending',created_at:new Date().toISOString()});renderCourses();if(S.activeCourseId===courseId)await openCourseScreen(courseId);alert('Đã gửi yêu cầu đăng ký. Admin sẽ duyệt và thêm bạn vào khóa học sau khi kiểm tra.')}
window.filterCourseStudents=function(keyword){if(!S.activeCourseId)return;renderCourseStudentPanel(S.activeCourseId,keyword,{keepSearchFocus:true})}
window.addStudentToCourse=async function(studentId){if(S.role!=='admin'||!S.activeCourseId||!studentId)return;const course=S.courses.find(x=>x.id===S.activeCourseId);const student=(S.studentDirectory||[]).find(x=>x.id===studentId);if(!course||!student)return;const{error}=await sb.from('course_enrollments').insert({course_id:S.activeCourseId,student_id:studentId});if(error){if(String(error.message||'').toLowerCase().includes('duplicate')){alert('Học sinh này đã có trong khóa học rồi.')}else{alert('Không thể thêm học sinh vào khóa học: '+error.message)}return}S.enrollments.push({course_id:S.activeCourseId,student_id:studentId});await window.AppAdminTools?.recordAudit?.('course_student_added',{target_type:'course',target_id:S.activeCourseId,course_name:course.name,student_id:studentId,student_name:student.full_name||null});if(window.NotificationHelper){try{await window.NotificationHelper.createNotification({userId:studentId,type:'course_enrolled',title:`Bạn đã được thêm vào khóa học ${course.name}`,message:`Admin vừa thêm bạn vào khóa học "${course.name}".`,refId:S.activeCourseId,targetUrl:`courses.html?courseId=${encodeURIComponent(S.activeCourseId)}`,meta:{courseId:S.activeCourseId,courseName:course.name}})}catch(error){console.warn('Không gửi được thông báo thêm học sinh vào khóa học',error)}}const input=document.getElementById('courseStudentSearch');renderCourseStudentPanel(S.activeCourseId,input?.value||'');alert(`Đã thêm ${student.full_name||'học sinh'} vào khóa học ${course.name}.`)}
async function processCourseRequest(requestId,nextStatus,{silent=false}={}){if(S.role!=='admin'||!requestId)return false;const req=S.requests.find(x=>x.id===requestId);if(!req)return false;const course=S.courses.find(x=>x.id===req.course_id);if(nextStatus==='approved'){const { error: enrollErr } = await sb.from('course_enrollments').insert({course_id:req.course_id,student_id:req.student_id});if(enrollErr && !String(enrollErr.message||'').toLowerCase().includes('duplicate')){if(!silent)alert('Không thể thêm học sinh vào khóa học: '+enrollErr.message);return false}}const { error:updateErr } = await sb.from('course_registration_requests').update({status:nextStatus,handled_by:S.user.id,handled_at:new Date().toISOString()}).eq('id',requestId);if(updateErr){if(!silent)alert(`Không thể ${nextStatus==='approved'?'duyệt':'từ chối'} yêu cầu: `+updateErr.message);return false}if(nextStatus==='approved'&&!S.enrollments.some(x=>x.course_id===req.course_id&&x.student_id===req.student_id))S.enrollments.push({course_id:req.course_id,student_id:req.student_id});req.status=nextStatus;req.handled_by=S.user.id;req.handled_at=new Date().toISOString();await window.AppAdminTools?.recordAudit?.(nextStatus==='approved'?'course_request_approved':'course_request_rejected',{target_type:'course_registration_request',target_id:requestId,course_id:req.course_id,course_name:course?.name||null,student_id:req.student_id});if(window.NotificationHelper){try{await window.NotificationHelper.createNotification({userId:req.student_id,type:nextStatus==='approved'?'course_request_approved':'course_request_rejected',title:nextStatus==='approved'?`Yêu cầu đăng ký ${course?.name||'khóa học'} đã được duyệt`:`Yêu cầu đăng ký ${course?.name||'khóa học'} chưa được duyệt`,message:nextStatus==='approved'?`Admin đã duyệt yêu cầu đăng ký khóa học "${course?.name||'Khóa học'}" của bạn.`:`Yêu cầu đăng ký khóa học "${course?.name||'Khóa học'}" của bạn đã bị từ chối.`,refId:req.course_id,targetUrl:`courses.html?courseId=${encodeURIComponent(req.course_id)}`,meta:{courseId:req.course_id,courseName:course?.name||null}})}catch(error){console.warn(nextStatus==='approved'?'Không gửi được thông báo duyệt yêu cầu khóa học':'Không gửi được thông báo từ chối yêu cầu khóa học',error)}}return true}
window.approveCourseRequest=async function(requestId){const ok=await processCourseRequest(requestId,'approved');if(!ok)return;const req=S.requests.find(x=>x.id===requestId);renderCourseStudentPanel(req?.course_id||S.activeCourseId,(document.getElementById('courseStudentSearch')||{}).value||'');renderCourses();alert('Đã duyệt yêu cầu và thêm học sinh vào khóa học.')}
window.rejectCourseRequest=async function(requestId){const ok=await processCourseRequest(requestId,'rejected');if(!ok)return;const req=S.requests.find(x=>x.id===requestId);renderCourseStudentPanel(req?.course_id||S.activeCourseId,(document.getElementById('courseStudentSearch')||{}).value||'');renderCourses();alert('Đã từ chối yêu cầu đăng ký.')}
window.approveAllCourseRequests=async function(){if(S.role!=='admin'||!S.activeCourseId)return;const pending=S.requests.filter(x=>x.course_id===S.activeCourseId&&x.status==='pending');if(!pending.length)return alert('Không có yêu cầu nào đang chờ duyệt.');if(!confirm(`Duyệt tất cả ${pending.length} yêu cầu đăng ký của khóa học này?`))return;let success=0;for(const req of pending){if(await processCourseRequest(req.id,'approved',{silent:true}))success++}renderCourseStudentPanel(S.activeCourseId,(document.getElementById('courseStudentSearch')||{}).value||'');renderCourses();alert(success===pending.length?`Đã duyệt ${success} yêu cầu.`:`Đã duyệt ${success}/${pending.length} yêu cầu. Vui lòng kiểm tra lại các yêu cầu còn lại.`)}
window.rejectAllCourseRequests=async function(){if(S.role!=='admin'||!S.activeCourseId)return;const pending=S.requests.filter(x=>x.course_id===S.activeCourseId&&x.status==='pending');if(!pending.length)return alert('Không có yêu cầu nào đang chờ duyệt.');if(!confirm(`Từ chối tất cả ${pending.length} yêu cầu đăng ký của khóa học này?`))return;let success=0;for(const req of pending){if(await processCourseRequest(req.id,'rejected',{silent:true}))success++}renderCourseStudentPanel(S.activeCourseId,(document.getElementById('courseStudentSearch')||{}).value||'');renderCourses();alert(success===pending.length?`Đã từ chối ${success} yêu cầu.`:`Đã từ chối ${success}/${pending.length} yêu cầu. Vui lòng kiểm tra lại các yêu cầu còn lại.`)}
function closeCourseScreen(){E.screen.classList.remove('show');S.activeCourseId=null}
function getOpenDate(startDate,openDay){if(!startDate)return new Date();const d=new Date(startDate);d.setDate(d.getDate()+Math.max(0,Number(openDay||1)-1));return d}
function startOfDay(d){const x=new Date(d);x.setHours(0,0,0,0);return x}
function getVisibleSessions(course){const all=S.sessions.filter(x=>x.course_id===course.id).sort((a,b)=>a.session_order-b.session_order);if(S.role==='admin'||S.role==='teacher')return all;if(!isEnrolled(course.id))return all.filter(x=>x.is_preview);return all.filter(x=>x.is_preview||startOfDay(getOpenDate(course.start_date,x.open_day)).getTime()<=startOfDay(new Date()).getTime())}
function getExamResultInfo(courseId,examId){const results=getCourseResults(courseId,examId).sort((a,b)=>(b.attempt_no||0)-(a.attempt_no||0));if(S.role==='admin'||S.role==='teacher')return{results,submitted:results.filter(x=>x.submitted_at),lastSubmitted:null,inProgress:null};const submitted=results.filter(x=>x.submitted_at);return{results,submitted,lastSubmitted:submitted[0]||null,inProgress:submitted.length?null:(results.find(x=>!x.submitted_at&&(x.seconds_left??0)>0)||null)}}
function renderPracticeExam(course,exam){const info=getExamResultInfo(course.id,exam.id);const boxStyle='border:1px solid #bfdbfe;background:linear-gradient(180deg,#f8fbff 0%,#eef6ff 100%);box-shadow:0 10px 24px rgba(29,107,209,.08)';const header='<div style="font-size:.72rem;font-weight:800;letter-spacing:.06em;text-transform:uppercase;color:#1d4ed8;margin-bottom:10px">Đề luyện tập</div>';if(S.role==='admin'||S.role==='teacher'){return `<div class="exam-box" style="${boxStyle}">${header}<div class="exam-top"><div class="exam-main"><div class="exam-title">${esc(exam.title)}</div><div class="exam-meta">⏱ ${exam.duration_minutes||0} phút • 🏆 ${exam.total_points||0} điểm</div></div><div class="exam-actions"><button class="submitted-badge" type="button" data-submissions="${course.id}|${exam.id}">${info.submitted.length} bài đã nộp</button></div></div></div>`}let scoreBadge='',actionBtn='';if(info.lastSubmitted){const score=info.lastSubmitted.score_total??info.lastSubmitted.score_auto??'?';scoreBadge=`<span class="score-badge">✓ ${score} / ${exam.total_points||0} đ</span>`}if(info.inProgress){const secsLeft=Math.max(0,(info.inProgress.seconds_left||0)-300),m=Math.floor(secsLeft/60),s=secsLeft%60;actionBtn=`<button class="btn btn-outline btn-sm" type="button" data-practice="${exam.id}">▶ Làm bài tiếp (${m}:${String(s).padStart(2,'0')})</button>`}else if(info.lastSubmitted){actionBtn=`<button class="btn btn-outline btn-sm" type="button" data-practice="${exam.id}">👁 Xem lại</button>`}else{actionBtn=`<button class="btn btn-primary btn-sm" type="button" data-practice="${exam.id}">📝 Làm bài</button>`}return `<div class="exam-box ${info.lastSubmitted?'done':''}" style="${boxStyle}">${header}<div class="exam-top"><div class="exam-main"><div class="exam-title">${esc(exam.title)}</div><div class="exam-meta">⏱ ${exam.duration_minutes||0} phút • 🏆 ${exam.total_points||0} điểm</div></div><div class="exam-actions">${scoreBadge}${actionBtn}</div></div></div>`}
function renderSession(course,s){const l=S.lessons.find(x=>x.id===s.lesson_id),exam=S.exams.find(x=>x.id===s.exam_id),d=getOpenDate(course.start_date,s.open_day),summary=l?.summary?`<p>${esc(l.summary)}</p>`:'';return `<div class="session"><div class="order" style="background:linear-gradient(135deg,#0f3c73 0%,#1d6bd1 100%);box-shadow:0 12px 28px rgba(15,60,115,.18);border:none"><strong style="font-size:.72rem;letter-spacing:.08em;text-transform:uppercase;color:rgba(255,255,255,.78)">Buổi học</strong><span style="font-size:1.4rem">${s.session_order}</span></div><div><h5 style="margin-top:8px">${esc(l?.name||'Chưa có tên bài học')}</h5>${summary}<div class="muted" style="margin-top:8px">Mở vào ngày thứ ${s.open_day||1} của khóa • ${fmtDate(d.toISOString())}${s.is_preview?' • Học thử':''}</div><div class="practice" style="margin-top:10px">${l?.lecture_video_url?`<a class="btn btn-outline btn-sm" href="${escAttr(l.lecture_video_url)}" target="_blank" rel="noopener">Video bài giảng</a>`:''}${l?.solution_video_url?`<a class="btn btn-outline btn-sm" href="${escAttr(l.solution_video_url)}" target="_blank" rel="noopener">Video chữa bài</a>`:''}${l?.document_link?`<a class="btn btn-outline btn-sm" href="${escAttr(l.document_link)}" target="_blank" rel="noopener">Tài liệu</a>`:''}</div>${exam?renderPracticeExam(course,exam):''}</div><div class="actions" style="flex-direction:column;align-items:flex-end">${S.role==='admin'?`<button class="btn btn-outline btn-sm" type="button" data-session-edit="${s.id}">Sửa buổi</button><button class="btn btn-danger btn-sm" type="button" data-session-delete="${s.id}">Xóa buổi</button>`:''}</div></div>`}
async function openCourseScreen(courseId){const c=S.courses.find(x=>x.id===courseId);if(!c)return;S.activeCourseId=courseId;E.screen.classList.add('show');E.screenTitle.textContent=c.name||'Chi tiết khóa học';E.screenEditBtn.classList.toggle('hidden',S.role!=='admin');E.openSessionBtn.classList.toggle('hidden',S.role!=='admin');const grade=S.grades.find(x=>x.id===c.grade_id)?.name||'Chưa thiết lập',subject=S.subjects.find(x=>x.id===c.subject_id)?.name||'Chưa thiết lập',managers=getManagers(c.id),enrolled=isEnrolled(c.id),pendingRequest=getPendingRequest(c.id),allCount=S.sessions.filter(x=>x.course_id===c.id).length||c.planned_sessions||0;E.screenRegisterBtn.classList.toggle('hidden',!(S.role==='student'&&!enrolled&&!pendingRequest));E.registerBanner.classList.toggle('hidden',!(S.role==='student'&&!enrolled&&!pendingRequest));E.summaryBox.innerHTML=`<div class="chips"><span class="pill soft">${c.status==='open'?'Đang mở':'Đã đóng'}</span><span class="pill soft">${esc(grade)}</span><span class="pill soft">${esc(subject)}</span><span class="pill soft">${allCount} buổi</span>${pendingRequest?'<span class="pill soft">Đang chờ duyệt</span>':''}</div><p style="margin:14px 0 0;color:#607089;line-height:1.7">${linkify(esc(c.description||'Chưa có mô tả khóa học.'))}</p><div class="meta" style="margin-top:16px"><div><span>Thời gian khóa học</span><strong>${fmtDate(c.start_date)} - ${fmtDate(c.end_date)}</strong></div><div><span>Học phí</span><strong>${fmtMoney(c.tuition_fee)}</strong></div><div><span>Quyền truy cập</span><strong>${S.role==='student'?(enrolled?'Đã được thêm vào khóa học':pendingRequest?'Đã gửi yêu cầu, đang chờ admin duyệt':'Chỉ xem buổi học thử, cần admin thêm thủ công'):'Quản trị / giáo viên'}</strong></div><div><span>Đăng ký</span><strong>${S.role==='student'?'Gửi yêu cầu vào danh sách chờ duyệt':'Admin thêm thủ công học sinh'}</strong></div></div><div style="margin-top:14px"><div class="muted" style="margin-bottom:8px">Giáo viên quản lý</div><div class="teachers">${managers.length?managers.map(t=>`<span class="teacher"><img src="${escAttr(t.avatar_url||avatarFallback)}"><span>${esc(t.full_name||'Giáo viên')}</span></span>`).join(''):`<span class="muted">Chưa gán giáo viên quản lý</span>`}</div></div>`;if(S.role==='admin'){try{await ensureStudentDirectory();renderCourseStudentPanel(c.id)}catch(error){if(E.courseStudentPanel){E.courseStudentPanel.classList.remove('hidden');E.courseStudentPanel.innerHTML=`<h4 style="margin:0 0 12px">Học sinh trong khóa học</h4><div class="muted">Không tải được danh sách học sinh: ${esc(error.message||'Lỗi không xác định')}</div>`}}}else if(E.courseStudentPanel){E.courseStudentPanel.classList.add('hidden');E.courseStudentPanel.innerHTML=''}const list=getVisibleSessions(c);E.sessionList.innerHTML=list.length?list.map(s=>renderSession(c,s)).join(''):`<div class="empty"><strong>Chưa có buổi học nào</strong><div class="muted">Admin có thể thêm buổi học đầu tiên cho khóa này.</div></div>`;document.querySelectorAll('[data-session-edit]').forEach(b=>b.onclick=()=>openSessionModal(b.dataset.sessionEdit));document.querySelectorAll('[data-session-delete]').forEach(b=>b.onclick=()=>deleteSession(b.dataset.sessionDelete));document.querySelectorAll('[data-practice]').forEach(b=>b.onclick=()=>openPractice(b.dataset.practice,c.id));document.querySelectorAll('[data-submissions]').forEach(b=>b.onclick=()=>{const[x,y]=b.dataset.submissions.split('|');openSubmissionModal(x,y)})}
function openPractice(examId,courseId){window.open(`course_practice.html?examId=${encodeURIComponent(examId)}&courseId=${encodeURIComponent(courseId)}`,'_blank')}
function openSessionModal(sessionId=null){if(S.role!=='admin'||!S.activeCourseId)return;S.editingSessionId=sessionId;E.sessionForm.reset();fillExams('');const next=S.sessions.filter(x=>x.course_id===S.activeCourseId).length+1;document.getElementById('sessionOrder').value=next;document.getElementById('sessionOpenDay').value=next;document.getElementById('sessionPreview').checked=false;document.getElementById('sessionDocumentLink').value='';E.sessionModalTitle.textContent=sessionId?'Sửa buổi học':'Thêm buổi học';if(sessionId){const s=S.sessions.find(x=>x.id===sessionId),l=S.lessons.find(x=>x.id===s?.lesson_id);if(!s||!l)return;document.getElementById('sessionOrder').value=s.session_order||'';document.getElementById('sessionOpenDay').value=s.open_day||1;document.getElementById('sessionLessonName').value=l.name||'';document.getElementById('sessionLessonSummary').value=l.summary||'';document.getElementById('sessionLectureVideo').value=l.lecture_video_url||'';document.getElementById('sessionSolutionVideo').value=l.solution_video_url||'';document.getElementById('sessionDocumentLink').value=l.document_link||'';document.getElementById('sessionPreview').checked=!!s.is_preview;fillExams(s.exam_id||'')}E.sessionModal.classList.add('show')}
function closeSessionModal(){E.sessionModal.classList.remove('show');S.editingSessionId=null}
async function submitSessionForm(ev){ev.preventDefault();if(S.role!=='admin'||!S.activeCourseId)return;const lessonPayload={name:document.getElementById('sessionLessonName').value.trim(),summary:document.getElementById('sessionLessonSummary').value.trim(),lecture_video_url:document.getElementById('sessionLectureVideo').value.trim()||null,solution_video_url:document.getElementById('sessionSolutionVideo').value.trim()||null,document_link:document.getElementById('sessionDocumentLink').value.trim()||null,created_by:S.user.id};if(!lessonPayload.name)return alert('Tên bài học không được để trống.');if(lessonPayload.document_link&&!/^https?:\/\/(drive|docs)\.google\.com\//i.test(lessonPayload.document_link))return alert('Link tài liệu phải là link Google Drive hoặc Google Docs.');const sessionPayload={course_id:S.activeCourseId,session_order:Number(document.getElementById('sessionOrder').value),open_day:Number(document.getElementById('sessionOpenDay').value),is_preview:document.getElementById('sessionPreview').checked,exam_id:document.getElementById('sessionExamId').value||null,created_by:S.user.id};const isEditing=!!S.editingSessionId;if(S.editingSessionId){const current=S.sessions.find(x=>x.id===S.editingSessionId);const{error:le}=await sb.from('lessons').update(lessonPayload).eq('id',current.lesson_id);if(le)return alert('Không thể cập nhật bài học: '+le.message);const{error:se}=await sb.from('course_sessions').update(sessionPayload).eq('id',S.editingSessionId);if(se)return alert('Không thể cập nhật buổi học: '+se.message)}else{const{data:l,error:le}=await sb.from('lessons').insert(lessonPayload).select('id').single();if(le)return alert('Không thể tạo bài học: '+le.message);const{error:se}=await sb.from('course_sessions').insert({...sessionPayload,lesson_id:l.id});if(se)return alert('Không thể tạo buổi học: '+se.message)}const course=S.courses.find(x=>x.id===S.activeCourseId);await window.AppAdminTools?.recordAudit?.(isEditing?'course_session_updated':'course_session_created',{target_type:'course_session',target_id:S.editingSessionId||null,course_id:S.activeCourseId,course_name:course?.name||null,session_order:sessionPayload.session_order,lesson_name:lessonPayload.name,has_exam:!!sessionPayload.exam_id});if(window.NotificationHelper){try{const extras=[lessonPayload.lecture_video_url?'video bài giảng':'',lessonPayload.solution_video_url?'video chữa bài':'',lessonPayload.document_link?'tài liệu tham khảo':'',sessionPayload.exam_id?'đề luyện tập':''].filter(Boolean);await window.NotificationHelper.notifyCourseStudents(S.activeCourseId,{type:isEditing?'course_session_updated':'course_session_added',title:`${course?.name||'Khóa học'} có buổi học ${isEditing?'được cập nhật':'mới'}`,message:`Buổi ${sessionPayload.session_order}: ${lessonPayload.name}${extras.length?` vừa có ${extras.join(', ')}.`:'.'}`,refId:S.activeCourseId,targetUrl:`courses.html?courseId=${encodeURIComponent(S.activeCourseId)}`,meta:{courseId:S.activeCourseId,courseName:course?.name||null,sessionOrder:sessionPayload.session_order,lessonName:lessonPayload.name,hasLectureVideo:!!lessonPayload.lecture_video_url,hasSolutionVideo:!!lessonPayload.solution_video_url,hasDocumentLink:!!lessonPayload.document_link,hasPracticeExam:!!sessionPayload.exam_id}})}catch(error){console.warn('Không gửi được thông báo buổi học khóa học',error)}}closeSessionModal();await loadData();openCourseScreen(S.activeCourseId)}
async function deleteSession(id){if(S.role!=='admin')return;if(!confirm('Bạn có chắc muốn xóa buổi học này không?'))return;const s=S.sessions.find(x=>x.id===id);const{error}=await sb.from('course_sessions').delete().eq('id',id);if(error)return alert('Không thể xóa buổi học: '+error.message);if(s?.lesson_id)await sb.from('lessons').delete().eq('id',s.lesson_id);await window.AppAdminTools?.recordAudit?.('course_session_deleted',{target_type:'course_session',target_id:id,course_id:S.activeCourseId,lesson_id:s?.lesson_id||null,session_order:s?.session_order||null});await loadData();openCourseScreen(S.activeCourseId)}
async function openSubmissionModal(courseId,examId){const course=S.courses.find(x=>x.id===courseId),exam=S.exams.find(x=>x.id===examId);if(!course||!exam)return;const results=getCourseResults(courseId,examId).filter(x=>x.submitted_at);const studentIds=[...new Set(results.map(x=>x.student_id))];let students=[];if(studentIds.length){const{data}=await sb.from('users').select('id,full_name,avatar_url').in('id',studentIds);students=data||[]}const studentMap=Object.fromEntries(students.map(x=>[x.id,x]));const latestByStudent={};results.forEach(x=>{if(!latestByStudent[x.student_id])latestByStudent[x.student_id]=x});S.submissionContext={courseId,examId};E.submissionModalTitle.textContent=`Bài đã nộp - ${exam.title}`;E.submissionBody.innerHTML=`<div style="display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap"><div><div style="font-weight:700;color:var(--navy)">${esc(course.name)}</div><div class="muted">${results.length} bài đã nộp trong khóa học này</div></div><div class="score-badge">${exam.total_points||0} điểm</div></div>${results.length?`<div style="overflow:auto;border:1px solid rgba(39,58,91,.08);border-radius:16px;margin-top:16px"><table style="width:100%;border-collapse:collapse"><thead><tr style="background:#0f3c73;color:#fff"><th style="padding:12px;text-align:left">Học sinh</th><th style="padding:12px;text-align:center">Tự động</th><th style="padding:12px;text-align:center">Tự luận</th><th style="padding:12px;text-align:center">Tổng</th><th style="padding:12px;text-align:center">Nộp lúc</th><th style="padding:12px;text-align:center">Chi tiết</th></tr></thead><tbody>${Object.values(latestByStudent).map(r=>{const st=studentMap[r.student_id];return `<tr style="border-bottom:1px solid rgba(39,58,91,.08)"><td style="padding:12px"><div style="display:flex;align-items:center;gap:10px"><img src="${escAttr(st?.avatar_url||avatarFallback)}" style="width:36px;height:36px;border-radius:50%;object-fit:cover"><strong style="color:var(--navy)">${esc(st?.full_name||'Học sinh')}</strong></div></td><td style="padding:12px;text-align:center">${r.score_auto??'—'}</td><td style="padding:12px;text-align:center">${r.score_essay??'—'}</td><td style="padding:12px;text-align:center;font-weight:700;color:var(--navy)">${r.score_total??r.score_auto??'—'}</td><td style="padding:12px;text-align:center">${fmtDateTime(r.submitted_at)}</td><td style="padding:12px;text-align:center"><button class="btn btn-outline btn-sm" type="button" data-open-review="${r.id}|${exam.id}|${escAttr(st?.full_name||'Học sinh')}">Xem bài</button></td></tr>`}).join('')}</tbody></table></div>`:`<div class="empty" style="margin-top:16px"><strong>Chưa có bài nộp nào</strong><div class="muted">Bài luyện tập này chưa có học sinh làm trong khóa học này.</div></div>`}`;E.submissionModal.classList.add('show');document.querySelectorAll('[data-open-review]').forEach(b=>b.onclick=()=>{const[rid,eid,name]=b.dataset.openReview.split('|');openSubmissionReview(rid,eid,name)})}
async function openSubmissionReview(resultId,examId,studentName){const{data:result}=await sb.from('exam_results').select('*').eq('id',resultId).single();const[{data:answers},{data:eqs},{data:exam}]=await Promise.all([sb.from('exam_answers').select('question_id,answer,is_correct,score_earned').eq('result_id',resultId),sb.from('exam_questions').select('*,question:question_bank(*)').eq('exam_id',examId).order('order_no'),sb.from('exams').select('title,total_points').eq('id',examId).single()]);const ansMap={};(answers||[]).forEach(a=>ansMap[a.question_id]=a);const sorted=(eqs||[]).slice().sort((a,b)=>(a.order_no??0)-(b.order_no??0)).filter(eq=>eq.question);const essayQs=sorted.filter(eq=>eq.question.question_type==='essay');const hasEssay=essayQs.length>0,scoreAuto=result?.score_auto??0,scoreEssay=result?.score_essay??0,scoreTotal=result?.score_total;E.submissionModalTitle.textContent=`Xem bài - ${studentName}`;E.submissionBody.innerHTML=`<div style="display:grid;gap:16px"><div style="display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap"><div style="display:flex;gap:10px;align-items:center"><button class="btn btn-outline btn-sm" type="button" id="backToSubmissionList">← Quay lại</button><div><div style="font-weight:700;color:var(--navy)">${esc(studentName)}</div><div class="muted">${esc(exam?.title||'Đề luyện tập')} • Nộp lúc ${fmtDateTime(result?.submitted_at)}</div></div></div><div style="font-size:.88rem;color:var(--ink-mid);text-align:right">Tự động: <b>${scoreAuto}</b><br>Tự luận: <b id="essayTotalText">${scoreEssay||0}</b><br><span style="color:var(--navy);font-weight:700">Tổng: <span id="grandTotalText">${scoreTotal??'Chưa chấm'}</span> / ${exam?.total_points||0}</span></div></div><div id="reviewWrap"></div>${hasEssay?`<div style="display:flex;justify-content:flex-end"><button class="btn btn-primary" type="button" id="saveEssayScoresBtn">Lưu điểm tự luận</button></div>`:''}</div>`;const wrap=document.getElementById('reviewWrap');if(window.buildReviewCards)wrap.appendChild(window.buildReviewCards(sorted,ansMap,hasEssay));window._courseEssayQIds=essayQs.map(eq=>({qid:eq.question.id,points:eq.points}));window._courseEssayScoreAuto=scoreAuto;document.getElementById('backToSubmissionList')?.addEventListener('click',()=>{if(S.submissionContext)openSubmissionModal(S.submissionContext.courseId,S.submissionContext.examId)});document.getElementById('saveEssayScoresBtn')?.addEventListener('click',()=>saveEssayScores(resultId,exam?.total_points||0))}
async function saveEssayScores(resultId,totalPts){let essaySum=0;const updates=[];for(const{qid,points}of(window._courseEssayQIds||[])){const val=parseFloat(document.getElementById('cv_essay_'+qid)?.value||0);if(!Number.isFinite(val)||val<0)return alert('Điểm tự luận phải là số không âm.');if(Number.isFinite(points)&&val>points)return alert(`Điểm câu tự luận không được vượt quá ${points}.`);essaySum+=val;updates.push({qid,val})}for(const item of updates){const{error}=await sb.from('exam_answers').update({score_earned:item.val}).eq('result_id',resultId).eq('question_id',item.qid);if(error)return alert('Không thể lưu điểm tự luận: '+error.message)}const total=Math.round(((window._courseEssayScoreAuto||0)+essaySum)*100)/100;const{error:updateErr}=await sb.from('exam_results').update({score_essay:Math.round(essaySum*100)/100,score_total:total}).eq('id',resultId);if(updateErr)return alert('Không thể cập nhật tổng điểm: '+updateErr.message);window.AppAdminTools?.recordAudit?.('course_essay_score_saved',{target_type:'exam_result',target_id:resultId,score_essay:Math.round(essaySum*100)/100,score_total:total});alert(`Đã lưu điểm tự luận: ${total}/${totalPts}`);await loadData();if(S.submissionContext)openSubmissionModal(S.submissionContext.courseId,S.submissionContext.examId)}
function closeSubmissionModal(){E.submissionModal.classList.remove('show');S.submissionContext=null}
